'use strict';

// Semantic-version precedence sorting. See docs/registry.md for the contract
// and docs/conventions.md for the precedence rules (numeric core fields,
// pre-release lower than release, build metadata ignored for precedence).
//
// Returns the input version strings sorted ascending by SemVer precedence,
// each original string preserved verbatim (build metadata is not stripped),
// without mutating the input array.
function sortVersions(versions) {
  return versions.slice().sort((a, b) => compareSemVer(a, b));
}

function compareSemVer(a, b) {
  const pa = parse(a);
  const pb = parse(b);

  if (pa.major !== pb.major) return pa.major - pb.major;
  if (pa.minor !== pb.minor) return pa.minor - pb.minor;
  if (pa.patch !== pb.patch) return pa.patch - pb.patch;

  // A version with no pre-release has higher precedence than one with pre-release
  if (pa.preRelease === null && pb.preRelease === null) return 0;
  if (pa.preRelease === null) return 1;
  if (pb.preRelease === null) return -1;

  return comparePreRelease(pa.preRelease, pb.preRelease);
}

function comparePreRelease(aIds, bIds) {
  const len = Math.max(aIds.length, bIds.length);
  for (let i = 0; i < len; i++) {
    if (i >= aIds.length) return -1; // fewer fields = lower precedence
    if (i >= bIds.length) return 1;

    const aId = aIds[i];
    const bId = bIds[i];
    const aNum = /^\d+$/.test(aId);
    const bNum = /^\d+$/.test(bId);

    if (aNum && bNum) {
      const diff = parseInt(aId, 10) - parseInt(bId, 10);
      if (diff !== 0) return diff;
    } else if (aNum !== bNum) {
      // Numeric identifiers have lower precedence than alphanumeric
      return aNum ? -1 : 1;
    } else {
      if (aId < bId) return -1;
      if (aId > bId) return 1;
    }
  }
  return 0;
}

function parse(version) {
  // Strip build metadata before parsing (ignored for precedence)
  const [versionCore] = version.split('+');
  const [corePart, ...preParts] = versionCore.split('-');
  const [major, minor, patch] = corePart.split('.').map(Number);
  const preRelease = preParts.length > 0 ? preParts.join('-').split('.') : null;
  return { major, minor, patch, preRelease };
}

module.exports = { sortVersions };

